// Shared helpers for serving raw documentation content to agents.
// Used by the Markdown-for-Agents route (app/api/md) and the consolidated
// /llms-full.txt feed so the file-reading logic lives in one place.

import { promises as fs } from "node:fs";
import path from "node:path";
import { source } from "@/lib/source";

export function stripFrontmatter(raw: string): string {
	// Remove a leading YAML frontmatter block (--- ... ---) if present.
	const m = raw.match(/^---\n[\s\S]*?\n---\n?/);
	return m ? raw.slice(m[0].length) : raw;
}

// Read the raw MDX body (frontmatter stripped) for a page by its slug segments.
// Returns null when the source file isn't bundled (the caller falls back to the
// title + description). Mirrors the candidate resolution Fumadocs uses:
// `<slug>.mdx` or `<slug>/index.mdx` under content/docs.
export async function readDocBody(slugs: string[]): Promise<string | null> {
	const rel = slugs.join("/");
	const candidates = [
		path.join(process.cwd(), "content/docs", `${rel}.mdx`),
		path.join(process.cwd(), "content/docs", rel, "index.mdx"),
	];
	for (const file of candidates) {
		try {
			return stripFrontmatter(await fs.readFile(file, "utf-8")).trim();
		} catch {
			// try next candidate
		}
	}
	return null;
}

// Top-level section priority for agent-facing concatenation: narrative docs
// first, the large auto-generated reference last. Sections not listed sort to
// the end (before changelog is irrelevant — unknowns just trail).
export const SECTION_ORDER = [
	"getting-started",
	"foundations",
	"memory",
	"analytics",
	"guides",
	"cookbook",
	"skills",
	"agents",
	"hooks",
	"troubleshooting",
	"showcase",
	"reference",
	"changelog",
] as const;

export function orderedPages() {
	const rank = (slug0: string) => {
		const i = SECTION_ORDER.indexOf(slug0 as (typeof SECTION_ORDER)[number]);
		return i < 0 ? SECTION_ORDER.length : i;
	};
	return [...source.getPages()].sort(
		(a, b) => rank(a.slugs[0] ?? "") - rank(b.slugs[0] ?? ""),
	);
}
